        if score < best_score:
            best_score = score
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {Design an algorithm that prioritizes proximity over time window urgency by using a penalty that exponentially increases the closer the truck is to missing the time window, with a reduced impact of cooldown factor on clusters}

    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    best_score = float('inf')
    best_node = None
    cooldown_factor = 0.2  # Reduced cooldown impact to allow clustering

    for i, customer in enumerate(unvisited_customers):
        earliest, latest = time_windows[i]
        travel_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_to_customer

        # Exponential penalty based on proximity to end of time window
        if arrival_time < earliest:
            penalty = np.exp(earliest - arrival_time) - 1
        else:
            penalty = 0

        if arrival_time > latest:
            penalty += (arrival_time - latest) ** 2  # Changed to quadratic penalty for missing the window

        # Calculate a score incorporating penalties and travel time
        score = travel_to_customer + penalty

        # Check vicinity for clusters and adjust with a lower cooldown factor
        cluster_effect = 0
        for other_truck in all_truck_pos:
            cluster_effect += 1 / (np.linalg.norm(customer - other_truck) + 1)
        score += cluster_effect * cooldown_factor

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
